Bash(node -e "
const { questions, personalities } = require\(''./src/config/questions.js''\);
const allTypes = Object.values\(personalities\);

// 简化计算：每个选项的tags + 基础分值
function calcResult\(answers\) {
  const counts = {};

  Object.entries\(answers\).forEach\(\([qId, optIdx]\) => {
    const q = questions.find\(q => q.id === Number\(qId\)\);
    if \(!q || !q.options[optIdx]\) return;
    const opt = q.options[optIdx];

    // 基础分值转类型名
    const baseMap = { ''A'': ''热血派'', ''B'': ''理性派'', ''C'': ''战斗派'', ''D'': ''传统派'', ''E'': ''中立派'' };
    if \(baseMap[opt.scores]\) {
      counts[baseMap[opt.scores]] = \(counts[baseMap[opt.scores]] || 0\) + 1;
    }
    // tags
    if \(opt.tags\) {
      opt.tags.forEach\(t => { counts[t] = \(counts[t] || 0\) + 1; }\);
    }
  }\);

  // 特殊类型>=4优先
  const specials = [''王大爷'',''辽宁铁人'',''云端球迷'',''冠军球迷'',''对线王'',''懂王''];
  for \(const s of specials\) {
    if \(counts[s] >= 4\) return s;
  }

  // 最多匹配
  let max = null, maxVal = 0;
  Object.entries\(counts\).forEach\(\([k,v]\) => { if \(v > maxVal\) { maxVal = v; max = k; } }\);
  return max;
}

// 统计每个类型出现次数
const typeStats = {};
allTypes.forEach\(t => { typeStats[t.name] = 0; }\);

// 模拟随机测试10000次
for \(let i = 0; i < 10000; i++\) {
  const ans = {};
  for \(let q = 1; q <= 20; q++\) {
    ans[q] = Math.floor\(Math.random\(\) * 5\);
  }
  const result = calcResult\(ans\);
  if \(result && typeStats[result] !== undefined\) typeStats[result]++;
}

// 排序输出
const sorted = Object.entries\(typeStats\).sort\(\(a,b\) => b[1] - a[1]\);
console.log\(''\\n=== 随机10000次测试结果 ===''\);
console.log\(''类型          次数   概率''\);
console.log\(''------------------------''\);
sorted.forEach\(\([type, count]\) => {
  console.log\(type.padEnd\(12\) + count + ''  '' + \(count/100\).toFixed\(1\) + ''%''\);
}\);
")
